package com.vidaysalud.veterinaria.notificacionservicio.service;import com.vidaysalud.veterinaria.notificacionservicio.client.ClienteClient;import com.vidaysalud.veterinaria.notificacionservicio.dto.*;import com.vidaysalud.veterinaria.notificacionservicio.exception.*;import com.vidaysalud.veterinaria.notificacionservicio.model.*;import com.vidaysalud.veterinaria.notificacionservicio.repository.NotificacionRepository;import lombok.RequiredArgsConstructor;import lombok.extern.slf4j.Slf4j;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.LocalDateTime;import java.util.*;@Service @RequiredArgsConstructor @Slf4j @Transactional public class NotificacionService{private final NotificacionRepository r;private final ClienteClient c;@Transactional(readOnly=true)public List<NotificacionResponseDTO>listar(){return r.findAll().stream().map(this::dto).toList();}@Transactional(readOnly=true)public NotificacionResponseDTO buscar(Integer id){return dto(get(id));}@Transactional(readOnly=true)public List<NotificacionResponseDTO>cliente(Integer id){return r.findByIdClienteOrderByFechaCreacionDesc(id).stream().map(this::dto).toList();}public NotificacionResponseDTO crear(NotificacionRequestDTO d){c.validar(d.getIdCliente());Notificacion n=Notificacion.builder().idCliente(d.getIdCliente()).tipo(d.getTipo()).destinatario(d.getDestinatario().trim()).asunto(d.getAsunto().trim()).mensaje(d.getMensaje().trim()).estado(EstadoNotificacion.PENDIENTE).build();return dto(r.save(n));}public NotificacionResponseDTO enviar(Integer id){Notificacion n=get(id);if(n.getEstado()==EstadoNotificacion.ENVIADA)throw new ReglaNegocioException("La notificación ya fue enviada");n.setEstado(EstadoNotificacion.ENVIADA);n.setFechaEnvio(LocalDateTime.now());log.info("Notificación simulada enviada id={} a={}",id,n.getDestinatario());return dto(r.save(n));}public void eliminar(Integer id){r.delete(get(id));}private Notificacion get(Integer id){return r.findById(id).orElseThrow(()->new RecursoNoEncontradoException("Notificación no encontrada: "+id));}private NotificacionResponseDTO dto(Notificacion n){return NotificacionResponseDTO.builder().idNotificacion(n.getIdNotificacion()).idCliente(n.getIdCliente()).tipo(n.getTipo()).destinatario(n.getDestinatario()).asunto(n.getAsunto()).mensaje(n.getMensaje()).estado(n.getEstado()).fechaCreacion(n.getFechaCreacion()).fechaEnvio(n.getFechaEnvio()).build();}}